updated = 0
for yaml_file in sorted(base.glob("*.yaml")):
    with open(yaml_file) as fh:
        d = yaml.safe_load(fh)
    tid = d.get("template_id", "")
    if tid not in ALL_EXAMPLES:
        continue
    examples = ALL_EXAMPLES[tid]
    count = 0
    for s in d["sections"]:
        if s["key"] in examples:
            s["example"] = examples[s["key"]]
            count += 1
    with open(yaml_file, "w") as fh:
        yaml.dump(d, fh, allow_unicode=True, default_flow_style=False, sort_keys=False)
    if count > 0:
        print(f"  ✅ {yaml_file.name}: {count}/{len(d['sections'])} examples")
        updated += 1

print(f"\nTotal: {updated} templates updated with examples")
